import{_ as o,c as a,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Plataformas e Integrações: Configuração de IA Multi-Modelo","description":"Aprenda a configurar e gerenciar múltiplas plataformas de IA (Anthropic, OpenAI, Google, Copilot), domine mecanismos de fallback automático e seleção inteligente de modelos.","frontmatter":{"title":"Plataformas e Integrações: Configuração de IA Multi-Modelo","sidebarTitle":"Conecte suas Contas de IA","subtitle":"Plataformas e Integrações: Configuração de IA Multi-Modelo","description":"Aprenda a configurar e gerenciar múltiplas plataformas de IA (Anthropic, OpenAI, Google, Copilot), domine mecanismos de fallback automático e seleção inteligente de modelos.","order":40},"headers":[],"relativePath":"pt/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"pt/code-yeongyu/oh-my-opencode/platforms/index.md"}'),s={name:"pt/code-yeongyu/oh-my-opencode/platforms/index.md"};function n(t,e,d,l,p,c){return i(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="plataformas-e-integracoes" tabindex="-1">Plataformas e Integrações <a class="header-anchor" href="#plataformas-e-integracoes" aria-label="Permalink to &quot;Plataformas e Integrações&quot;">​</a></h1><p>Este capítulo apresenta como configurar e gerenciar múltiplos AI Providers (Anthropic, OpenAI, Google, GitHub Copilot, etc.), bem como o mecanismo de fallback automático multi-modelo do oh-my-opencode.</p><p>Ao concluir este capítulo, você dominará como fazer com que o sistema selecione inteligentemente o modelo de IA mais adequado com base no tipo de tarefa e nos modelos disponíveis, construindo fluxos de trabalho de orquestração multi-modelo eficientes e confiáveis.</p><h2 id="o-que-este-capitulo-abrange" tabindex="-1">O Que Este Capítulo Abrange <a class="header-anchor" href="#o-que-este-capitulo-abrange" aria-label="Permalink to &quot;O Que Este Capítulo Abrange&quot;">​</a></h2><p>Este capítulo é dividido em duas partes:</p><h3 id="_1-configuracao-do-provider" tabindex="-1">1. <a href="./provider-setup/">Configuração do Provider</a> <a class="header-anchor" href="#_1-configuracao-do-provider" aria-label="Permalink to &quot;1. [Configuração do Provider](provider-setup/)&quot;">​</a></h3><p>Aprenda a configurar vários AI Providers, incluindo:</p><ul><li>Anthropic Claude (primeira escolha do orquestrador principal)</li><li>OpenAI ChatGPT (especializado em revisão de arquitetura)</li><li>Google Gemini (análise de frontend e mídia)</li><li>GitHub Copilot (Provider de backup)</li><li>Z.ai Coding Plan e OpenCode Zen (serviços opcionais)</li></ul><p><strong>O Que Você Vai Aprender</strong>:</p><ul><li>✅ Configurar 6 AI Providers principais</li><li>✅ Usar o instalador interativo para configuração rápida</li><li>✅ Especificar os modelos mais adequados para diferentes agentes</li><li>✅ Usar o comando <code>doctor</code> para diagnosticar problemas de configuração</li></ul><p><strong>Tempo Estimado</strong>: 25-30 minutos</p><h3 id="_2-estrategia-multi-modelo" tabindex="-1">2. <a href="./model-resolution/">Estratégia Multi-Modelo</a> <a class="header-anchor" href="#_2-estrategia-multi-modelo" aria-label="Permalink to &quot;2. [Estratégia Multi-Modelo](model-resolution/)&quot;">​</a></h3><p>Aprofunde-se no mecanismo de prioridade em três etapas do sistema de resolução de modelos:</p><ul><li>Override do usuário (controle preciso)</li><li>Fallback do Provider (tolerância a falhas automática)</li><li>Padrão do sistema (solução de fallback)</li></ul><p><strong>O Que Você Vai Aprender</strong>:</p><ul><li>✅ Entender o fluxo de trabalho completo de resolução de modelos</li><li>✅ Especificar manualmente modelos com base nos requisitos da tarefa</li><li>✅ Aproveitar o fallback do Provider para melhorar a robustez do sistema</li><li>✅ Diagnosticar e resolver problemas de resolução de modelos</li></ul><p><strong>Tempo Estimado</strong>: 30-35 minutos</p><h2 id="caminho-de-aprendizado-recomendado" tabindex="-1">Caminho de Aprendizado Recomendado <a class="header-anchor" href="#caminho-de-aprendizado-recomendado" aria-label="Permalink to &quot;Caminho de Aprendizado Recomendado&quot;">​</a></h2><p>Recomendamos seguir esta ordem ao estudar este capítulo:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Instalação Completa] --&gt; B[Configuração do Provider]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Estratégia Multi-Modelo]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Funcionalidades Avançadas]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>Por que esta ordem?</strong></p><ol><li><strong>Configure primeiro, entenda depois</strong>: Aprenda primeiro como configurar cada Provider, depois entenda o mecanismo de resolução subjacente</li><li><strong>Do simples ao complexo</strong>: A configuração do Provider é operação básica, a estratégia multi-modelo é um conceito avançado</li><li><strong>A prática valida a teoria</strong>: Após configurar os Providers, você pode usar o comando <code>doctor</code> para verificar a eficácia da estratégia multi-modelo</li></ol><div class="tip custom-block"><p class="custom-block-title">Caminho de Início Rápido</p><p>Se você apenas deseja começar rapidamente, pode completar as etapas 1-4 de <a href="./provider-setup/">Configuração do Provider</a> (configurar Providers básicos) e aprender o restante conforme necessário posteriormente.</p></div><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><p>Antes de estudar este capítulo, certifique-se de que:</p><ul><li>✅ Completou <a href="./../installation/">Instalação e Configuração Inicial</a></li><li>✅ Instalou o OpenCode (versão &gt;= 1.0.150)</li><li>✅ Entende formatos básicos de arquivos de configuração JSON/JSONC</li><li>✅ Possui pelo menos uma assinatura de conta de AI Provider (Anthropic Claude recomendado)</li></ul><div class="warning custom-block"><p class="custom-block-title">E se eu não tiver uma conta de Provider?</p><p>Você pode aprender as etapas de configuração primeiro sem conectar-se a um Provider. O sistema usará o modelo padrão do OpenCode como fallback.</p></div><h2 id="perguntas-frequentes" tabindex="-1">Perguntas Frequentes <a class="header-anchor" href="#perguntas-frequentes" aria-label="Permalink to &quot;Perguntas Frequentes&quot;">​</a></h2><details><summary><strong>Preciso configurar todos os Providers?</strong></summary><p>Não. Você pode configurar apenas os Providers que mais usa (por exemplo, apenas Anthropic Claude). O mecanismo de fallback do Provider do oh-my-opencode usará automaticamente os Providers disponíveis.</p><p>No entanto, se você deseja aproveitar totalmente as vantagens da orquestração multi-modelo, recomendamos configurar pelo menos 2-3 Providers, para que o sistema possa selecionar automaticamente o modelo mais adequado com base no tipo de tarefa.</p></details><details><summary><strong>Qual é a diferença entre configuração do Provider e resolução de modelos?</strong></summary><ul><li><strong>Configuração do Provider</strong>: É a &quot;etapa de instalação&quot;, informando ao sistema quais serviços de IA você tem disponíveis</li><li><strong>Resolução de Modelos</strong>: É a &quot;lógica de decisão&quot;, como o sistema seleciona qual Provider usar para cada agente</li></ul><p>Analogia: Configuração do Provider é &quot;contratar membros da equipe&quot;, resolução de modelos é &quot;atribuir tarefas&quot;.</p></details><details><summary><strong>Posso modificar a configuração a qualquer momento?</strong></summary><p>Você pode modificar o arquivo de configuração a qualquer momento:</p><ul><li>Configuração do usuário: <code>~/.config/opencode/oh-my-opencode.json</code></li><li>Configuração do projeto: <code>.opencode/oh-my-opencode.json</code></li></ul><p>As alterações entram em vigor automaticamente na próxima vez que você usar um agente. Se você modificou a autenticação do Provider, precisa executar <code>opencode auth login</code> para autenticar novamente.</p></details><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode:</p><h3 id="caminho-recomendado-aprender-a-equipe-de-agentes-de-ia" tabindex="-1">Caminho Recomendado: Aprender a Equipe de Agentes de IA <a class="header-anchor" href="#caminho-recomendado-aprender-a-equipe-de-agentes-de-ia" aria-label="Permalink to &quot;Caminho Recomendado: Aprender a Equipe de Agentes de IA&quot;">​</a></h3><p>Continue aprendendo <a href="./../../advanced/ai-agents-overview/">Equipe de Agentes de IA: Visão Geral de 10 Especialistas</a> para entender como usar diferentes agentes para tarefas especializadas.</p><h3 id="caminho-avancado-personalizacao-profunda" tabindex="-1">Caminho Avançado: Personalização Profunda <a class="header-anchor" href="#caminho-avancado-personalizacao-profunda" aria-label="Permalink to &quot;Caminho Avançado: Personalização Profunda&quot;">​</a></h3><p>Se você já está familiarizado com a configuração básica, pode pular para <a href="./../../advanced/advanced-configuration/">Configuração Profunda: Gerenciamento de Agentes e Permissões</a> para aprender:</p><ul><li>Como personalizar prompts de agentes</li><li>Como definir permissões e escopos de acesso de agentes</li><li>Como criar agentes e Categorias personalizados</li></ul><h3 id="caminho-pratico-usar-o-planejamento-prometheus" tabindex="-1">Caminho Prático: Usar o Planejamento Prometheus <a class="header-anchor" href="#caminho-pratico-usar-o-planejamento-prometheus" aria-label="Permalink to &quot;Caminho Prático: Usar o Planejamento Prometheus&quot;">​</a></h3><p>Comece a usar <a href="./../../advanced/prometheus-planning/">Planejamento Prometheus: Coleta de Requisitos no Estilo de Entrevista</a> para experimentar o poder da orquestração multi-modelo através da colaboração real de agentes.</p><hr><p><strong>Começar</strong>: Comece sua jornada de orquestração multi-modelo com <a href="./provider-setup/">Configuração do Provider</a>!</p>`,42)])])}const g=o(s,[["render",n]]);export{m as __pageData,g as default};
